    return Profile.empty();
  }
}

// ── Subtle: order of catchError matters ──
Future<int> trickyCatch() {
  return computeSomething()
      .then((v) => v + 1)             // throws if v is null
      .catchError((e) {
        return 0;                     // ✅ recovers and the next .then sees 0
      })
      .then((v) => v * 2);            // runs on success OR after recovery
}

