// ── ✅ Capture the Future once in State ──
class Profile extends StatefulWidget {
  const Profile({super.key, required this.id});
  final String id;
  @override State<Profile> createState() => _ProfileState();
}

class _ProfileState extends State<Profile> {
  late Future<User> _user;

  @override
  void initState() {
    super.initState();
    _user = api.user(widget.id);
  }

  // React to id change from parent
  @override
  void didUpdateWidget(covariant Profile old) {
    super.didUpdateWidget(old);
    if (old.id != widget.id) {
      _user = api.user(widget.id);          // refetch only when id changes
    }
  }

  @override
  Widget build(BuildContext context) {
    return FutureBuilder<User>(
      future: _user,
      builder: (_, snap) {
        return switch (snap.connectionState) {
          ConnectionState.waiting => const _Spinner(),
          ConnectionState.done when snap.hasError => _Error(error: snap.error!),
          ConnectionState.done when snap.hasData  => _UserCard(user: snap.data!),
          _ => const SizedBox.shrink(),
        };
      },
    );
  }
}

// ── Refresh-on-pull pattern — set a new Future and let the builder pick it up ──
Future<void> _refresh() async {
  setState(() => _user = api.user(widget.id));
  await _user;                              // wait for the indicator to release
}

RefreshIndicator(onRefresh: _refresh, child: ...);

