// ── 1) Single-flight refresh ──
class TokenManager {
  Future<Tokens>? _refreshing;
  Tokens current = Tokens.empty();

  Future<Tokens> refresh() {
    // ✅ If a refresh is in flight, share its result
    return _refreshing ??= _doRefresh().whenComplete(() {
      _refreshing = null;
    });
  }

  Future<Tokens> _doRefresh() async {
    final next = await api.refresh(current.refreshToken);
    current = next;
    return next;
  }
}

// ── 2) Lock — serialize a sequence of writes ──
class DraftStore {
  final _lock = Lock();
  Draft _draft = Draft.empty();

  Future<void> applyEdit(Edit edit) {
    return _lock.synchronized(() async {
      final next = await applyTo(_draft, edit);
      await persistToDisk(next);
      _draft = next;
    });
  }
}
// Two concurrent applyEdit() calls run one after the other inside the lock.

// ── 3) Drain queue — events processed in order ──
class AnalyticsDrain {
  final _ctrl = StreamController<AnalyticsEvent>();
  AnalyticsDrain() { _ctrl.stream.asyncMap(_send).listen((_) {}); }
  void log(AnalyticsEvent e) => _ctrl.add(e);
  Future<void> _send(AnalyticsEvent e) async {
    try { await api.send(e); } catch (_) { /* drop */ }
  }
  void dispose() => _ctrl.close();
}

// ── 4) Optimistic concurrency — version field ──
class Tasks {
  Future<bool> rename(int id, String name, int expectedRev) async {
    final updated = await db.update(
      'tasks',
      {'name': name, 'rev': expectedRev + 1},
      where: 'id = ? AND rev = ?', whereArgs: [id, expectedRev],
    );
    return updated == 1;            // false ⇒ someone else won; refetch
  }
}

